module RefModule (  
    input clk,  
    input reset,  
    input start,  
    input [7:0] src_addr,  
    input [7:0] dest_addr,  
    input [3:0] data_size,  
    output reg done  
);  
    reg [3:0] unused_count;  
    reg transferring;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            done <= 0;  
            unused_count <= 0;  
            transferring <= 0;  
        end else if (start && !transferring) begin  
            transferring <= 1;  
            unused_count <= 0;  
            done <= 0;  
        end else if (transferring) begin  
            if (unused_count < data_size) begin  
                // Simulate data transfer logic here  
                unused_count <= unused_count + 1;  
            end else begin  
                transferring <= 0;  
                done <= 1;  
            end  
        end  
    end  
endmodule
